class Solution:
    def countKReducibleNumbers(self, s, k):
        MOD = 10 ** 9 + 7
        n = int(s, 2)
        def steps(x):
            cnt = 0
            while x != 1:
                x = bin(x).count('1')
                cnt += 1
            return cnt
        total = 0
        for x in range(1, n):
            if steps(x) <= k:
                total += 1
        return total % MOD

