class Solution:
    def countKReducibleNumbers(self, s, k):
        MOD = 10 ** 9 + 7
        n_bits = len(s)
        memo = {1: 0}
        def steps(m):
            if m in memo:
                return memo[m]
            r = 1 + steps(bin(m).count('1'))
            memo[m] = r
            return r
        allowed = [p for p in range(1, n_bits + 1) if steps(p) <= k - 1]
        C = [[0] * (n_bits + 1) for _ in range(n_bits + 1)]
        for i in range(n_bits + 1):
            C[i][0] = 1
            for j in range(1, i + 1):
                C[i][j] = (C[i - 1][j - 1] + C[i - 1][j]) % MOD
        ones_so_far = 0
        total = 0
        for i, ch in enumerate(s):
            if ch == '1':
                remaining = n_bits - 1 - i
                for p in allowed:
                    need = p - ones_so_far
                    if 0 <= need <= remaining:
                        total = (total + C[remaining][need]) % MOD
                ones_so_far += 1
        return total % MOD

