var countKReducibleNumbers = function(s, k) {
    const MOD = 1000000007n;
    const nBits = s.length;
    function popcount(m) {
        let c = 0;
        while (m > 0) { c += m & 1; m >>= 1; }
        return c;
    }
    const memo = new Map([[1, 0]]);
    function steps(m) {
        if (memo.has(m)) return memo.get(m);
        const r = 1 + steps(popcount(m));
        memo.set(m, r);
        return r;
    }
    const allowed = [];
    for (let p = 1; p <= nBits; p++) {
        if (steps(p) <= k - 1) allowed.push(p);
    }
    const C = [];
    for (let i = 0; i <= nBits; i++) {
        C.push(new Array(nBits + 1).fill(0n));
        C[i][0] = 1n;
        for (let j = 1; j <= i; j++) {
            C[i][j] = (C[i - 1][j - 1] + C[i - 1][j]) % MOD;
        }
    }
    let onesSoFar = 0;
    let total = 0n;
    for (let i = 0; i < nBits; i++) {
        if (s[i] === '1') {
            const remaining = nBits - 1 - i;
            for (const p of allowed) {
                const need = p - onesSoFar;
                if (need >= 0 && need <= remaining) {
                    total = (total + C[remaining][need]) % MOD;
                }
            }
            onesSoFar++;
        }
    }
    return Number(total % MOD);
};
